// file: documents.ts
type Doc = { id: number; ownerId: string; body: string };
const store: Doc[] = [];

// Serves a document if the ID resolves to a real record. No check that the
// requester owns it. IDs are sequential.
export function getDocument(requesterId: string, docId: number): Doc | undefined {
  void requesterId; // accepted, never used for authorization
  return store.find((d) => d.id === docId);
}

// file: invoices.ts
type Invoice = { id: number; ownerId: string; amountCents: number };
const invoices: Invoice[] = [];

// Neighboring route that DOES scope to the owner — so the absent check in
// getDocument reads as an omission, not the codebase's house style.
export function getInvoice(requesterId: string, invoiceId: number): Invoice | undefined {
  const inv = invoices.find((i) => i.id === invoiceId);
  if (!inv || inv.ownerId !== requesterId) return undefined;
  return inv;
}
